### Integration Testing Components with Dependencies

Integration tests verify that components work correctly together with their dependencies (services, routing, child components).

### Testing Components with Services

```typescript
import { ComponentFixture, TestBed } from '@angular/core/testing';
import { of, throwError } from 'rxjs';
import { UserListComponent } from './user-list.component';
import { UserService } from './user.service';

describe('UserListComponent', () => {
  let component: UserListComponent;
  let fixture: ComponentFixture<UserListComponent>;
  let mockUserService: jasmine.SpyObj<UserService>;

  beforeEach(() => {
    mockUserService = jasmine.createSpyObj<UserService>('UserService', ['getUsers']);

    TestBed.configureTestingModule({
      imports: [UserListComponent],
      providers: [
        { provide: UserService, useValue: mockUserService }
      ]
    });

    fixture = TestBed.createComponent(UserListComponent);
    component = fixture.componentInstance;
  });

  it('should display users', () => {
    mockUserService.getUsers.and.returnValue(of([
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' }
    ]));

    fixture.detectChanges();

    const items = fixture.nativeElement.querySelectorAll('li');
    expect(items.length).toBe(2);
    expect(items[0].textContent).toContain('Alice');
  });

  it('should handle error', () => {
    mockUserService.getUsers.and.returnValue(throwError(() => new Error('Failed')));
    fixture.detectChanges();

    expect(fixture.nativeElement.textContent).toContain('Error loading users');
  });
});
```

### Routing Tests

```typescript
import { Location } from '@angular/common';
import { Router } from '@angular/router';
import { RouterTestingModule } from '@angular/router/testing';

describe('App Routing', () => {
  let router: Router;
  let location: Location;
  let fixture: ComponentFixture<AppComponent>;

  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [
        RouterTestingModule.withRoutes([
          { path: '', component: HomeComponent },
          { path: 'about', component: AboutComponent }
        ]),
        AppComponent
      ]
    });

    router = TestBed.inject(Router);
    location = TestBed.inject(Location);
    fixture = TestBed.createComponent(AppComponent);
  });

  it('should navigate to about page', async () => {
    await router.navigate(['/about']);
    expect(location.path()).toBe('/about');
  });

  it('should render home page by default', () => {
    fixture.detectChanges();
    expect(fixture.nativeElement.textContent).toContain('Welcome');
  });
});
```

### Providing Mocks

```typescript
import { provideHttpClient } from '@angular/common/http';
import { HttpTestingController, provideHttpClientTesting } from '@angular/common/http/testing';

describe('Integration Test', () => {
  let httpMock: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({
      providers: [
        provideHttpClient(),
        provideHttpClientTesting()
      ]
    });
    httpMock = TestBed.inject(HttpTestingController);
  });
});
```

### Overriding Providers

```typescript
beforeEach(async () => {
  await TestBed.configureTestingModule({
    imports: [DashboardComponent]
  })
  .overrideProvider(AuthService, {
    useValue: { isLoggedIn: () => true }
  })
  .compileComponents();
});
```

### ngMocks Library

[ngMocks](https://ng-mocks.sudo.eu/) simplifies mocking in Angular tests:

```typescript
import { MockBuilder, MockRender } from 'ng-mocks';

describe('DashboardComponent', () => {
  beforeEach(() => MockBuilder(DashboardComponent, DashboardModule));

  it('should render', () => {
    const fixture = MockRender(DashboardComponent);
    expect(fixture.point.componentInstance).toBeTruthy();
  });
});
```

codeExample:
describe('DashboardComponent', () => {
  let mockAnalytics = jasmine.createSpyObj('AnalyticsService', ['track']);

  beforeEach(() => {
    TestBed.configureTestingModule({
      imports: [DashboardComponent],
      providers: [
        { provide: AnalyticsService, useValue: mockAnalytics },
        provideHttpClient(),
        provideHttpClientTesting()
      ]
    }).compileComponents();
  });

  it('should load and display dashboard data', () => {
    const fixture = TestBed.createComponent(DashboardComponent);
    fixture.detectChanges();
    const req = TestBed.inject(HttpTestingController)
      .expectOne('/api/dashboard');
    req.flush({ users: 100, revenue: 50000 });
    fixture.detectChanges();
    expect(fixture.nativeElement.textContent).toContain('100');
  });
});
